def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    length = len(bins)
    max_bin = np.max(bins) if length > 0 else 1
    min_bin = np.min(bins[bins > 0]) if np.any(bins > 0) else 1
    for i, capacity in enumerate(bins):
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
            continue
        if item == 0:
            priorities[i] = 0
            continue
        ratio = item / capacity
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        bonus = 0.0
        penalty = 0.0
        if ratio > 5:
            for k in range(5, 0, -1):
                penalty += ((ratio ** k) / (k**2 + 1)) * ((-1) ** k)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + j * 2))
            score = (ratio ** 6) / 5 + penalty * 2
            if item > capacity * 6:
                score *= 4
            else:
                score *= 2.5
            priorities[i] = score * decay
        elif 3 < ratio <= 5:
            for x in range(1, 10):
                sign = (-1) ** (x)
                score += sign * (np.log(ratio + 1) ** x) / (x + 3)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio + 2))
            score = abs(score) * decay * 15
            priorities[i] = score
        elif 1.5 < ratio <= 3:
            temp = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 7)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 6)
                else:
                    temp += (ratio ** p) / (p * 5)
            multiplier = 20 if ratio < 2 else 14 if ratio < 2.5 else 9
            bonus = 0
            if ratio > 2.7:
                for m in range(1, 8):
                    bonus += (np.sqrt(ratio) ** m) / (m + 4)
            score = abs(temp) * multiplier + bonus * 3
            priorities[i] = score
        elif 0.7 < ratio <= 1.5:
            temp_score = 0
            for p in range(1, 20):
                if p % 5 == 0:
                    temp_score -= (ratio ** p) / (p * 4)
                elif p % 4 == 0:
                    temp_score += (ratio ** p) / (p * 5)
                elif p % 3 == 0:
                    temp_score -= (ratio ** p) / (p * 3)
                else:
                    temp_score += (ratio ** p) / (p * 2)
            if ratio < 1.0:
                multiplier = 12
            elif ratio < 1.2:
                multiplier = 9
            else:
                multiplier = 6
            score = abs(temp_score) * multiplier
            if ratio > 1.3:
                extra_pen = 0
                for n in range(1, 10):
                    extra_pen += (ratio ** n) / (n + 2)
                score += extra_pen * 4
            priorities[i] = score
        elif 0 < ratio <= 0.7:
            temp_score = 0
            for p in range(1, 25):
                if p % 6 == 0:
                    temp_score += (ratio ** p) / (p * 7)
                elif p % 5 == 0:
                    temp_score -= (ratio ** p) / (p * 6)
                elif p % 4 == 0:
                    temp_score += (ratio ** p) / (p * 8)
                else:
                    temp_score -= (ratio ** p) / (p * 5)
            if ratio < 0.1:
                multiplier = 40
            elif ratio < 0.3:
                multiplier = 28
            elif ratio < 0.5:
                multiplier = 18
            else:
                multiplier = 10
            score = abs(temp_score) * multiplier
            if ratio > 0.6:
                extra_penalties = 0
                for n in range(1, 12):
                    extra_penalties += (ratio ** n) / (n + 3)
                score += extra_penalties * 5
            priorities[i] = score
        else:
            priorities[i] = np.inf
        if priorities[i] != np.inf:
            relative_size = (capacity - min_bin) / (max_bin - min_bin + 1e-8)
            scale_factor = 1 + (relative_size ** 2) * 2
            for _ in range(3):
                scale_factor *= (1 + ratio / (capacity + 1))
            priorities[i] *= scale_factor
        else:
            priorities[i] = np.inf
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        max_priority = np.max(priorities[finite_mask])
        min_priority = np.min(priorities[finite_mask])
        for i in range(length):
            if finite_mask[i]:
                priorities[i] = (priorities[i] - min_priority) / (max_priority - min_priority + 1e-9)
    return priorities
